// ---- Markexis lead pipeline: normalize -> Firecrawl enrich -> Groq score -> Supabase upsert ----
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = ($json.body) || $json || {};
const platforms = ["linkedin","instagram","google_maps","reddit","github","producthunt","yelp","twitter","g2","wellfound","facebook","hackernews"];
const sizes = ["1-10","11-50","51-200","201+","unknown"];
const clean = (v) => (typeof v === "string" ? v.trim() : v) || null;
function domainFrom(d, email) {
  if (d) { return String(d).replace(/^https?:\/\//i,"").replace(/^www\./i,"").split("/")[0].toLowerCase(); }
  if (email && email.includes("@")) {
    const dd = email.split("@")[1].toLowerCase();
    const free = ["gmail.com","yahoo.com","hotmail.com","outlook.com","icloud.com","proton.me"];
    if (!free.includes(dd)) return dd;
  }
  return null;
}
const email = clean(b.email) ? String(b.email).toLowerCase() : null;
let size = clean(b.company_size_signal); if (!sizes.includes(size)) size = "unknown";
let platform = clean(b.source_platform); if (!platforms.includes(platform)) platform = "unknown";
const lead = {
  name: clean(b.name), email, company: clean(b.company),
  domain: domainFrom(clean(b.domain), email),
  title: clean(b.title), location: clean(b.location),
  source_platform: platform, source_url: clean(b.source_url),
  raw_bio: clean(b.raw_bio), company_size_signal: size,
  scraped_at: b.scraped_at || new Date().toISOString()
};

// 1) Firecrawl enrich (best-effort)
let enriched = null, fcErr = null;
try {
  if (lead.domain) {
    const fc = await this.helpers.httpRequest({
      method: "POST", url: "https://api.firecrawl.dev/v1/scrape",
      headers: { Authorization: "Bearer " + ENV.FIRECRAWL_API_KEY, "Content-Type": "application/json" },
      body: { url: "https://" + lead.domain, formats: ["markdown"] }, json: true, timeout: 30000
    });
    enriched = (fc && fc.data && fc.data.markdown) ? String(fc.data.markdown).slice(0, 3500) : null;
  }
} catch (e) { fcErr = String(e && e.message || e).slice(0, 200); }

// 2) Groq ICP score
const SYSTEM = "You are a lead qualifier for Markexis, a premium B2B consulting firm specializing in:\n1. Revenue Growth & GTM Strategy\n2. Latin America Market Entry (Mexico, Brazil, Colombia, Argentina, Chile)\n3. AI Implementation in Marketing & Sales\n4. AI Data & Insights\n\nClassify the lead as PERFECT, GOOD, or NO_MATCH for Markexis.\n\nPERFECT (3+ criteria): title is CEO/Founder/CMO/VP Marketing/CRO/Head of Growth/VP Sales/Marketing Director; company is B2B SaaS/Fintech/Healthtech/CPG/tech startup/e-commerce with B2B; size 20-500; based in US/Canada/UK/EU/Australia (or a LatAm company wanting to scale); has a signal like Latin America/LATAM/Mexico/Brazil/Colombia/AI marketing/go-to-market/GTM/pipeline/Series A/just raised/scaling/expanding/growth strategy.\nGOOD (2 criteria, or promising but weak): right industry slightly wrong title; right title adjacent industry; LatAm company wanting better marketing.\nNO_MATCH (any disqualifier): local business; enterprise 5000+ employees; pre-revenue/pre-product; competitor agency/consultant; consumer-only no B2B; no budget signals.\n\nRespond ONLY with valid JSON, nothing else:\n{\"icp_score\":\"PERFECT|GOOD|NO_MATCH\",\"numeric_score\":1-10,\"reasoning\":\"one sentence\",\"latam_signal\":true|false,\"ai_signal\":true|false,\"growth_signal\":true|false,\"priority_action\":\"email_track_latam|email_track_ai|email_track_growth|linkedin_dm|skip\",\"personalization_hook\":\"one specific detail from their bio/company to open an email with\"}";
const USER = "Lead data:\nName: " + (lead.name||"") + "\nTitle: " + (lead.title||"") +
  "\nCompany: " + (lead.company||"") + "\nCompany size: " + (lead.company_size_signal||"") +
  "\nLocation: " + (lead.location||"") + "\nBio/Description: " + (lead.raw_bio||"") +
  "\nEnriched company info: " + (enriched||"none") + "\nSource platform: " + (lead.source_platform||"");
let parsed = {}, groqErr = null;
try {
  const gr = await this.helpers.httpRequest({
    method: "POST", url: "https://api.groq.com/openai/v1/chat/completions",
    headers: { Authorization: "Bearer " + ENV.GROQ_API_KEY, "Content-Type": "application/json" },
    body: { model: "llama-3.1-8b-instant", messages: [{role:"system",content:SYSTEM},{role:"user",content:USER}], temperature: 0.2, max_tokens: 512, response_format: { type: "json_object" } },
    json: true, timeout: 30000
  });
  parsed = JSON.parse(gr.choices[0].message.content);
} catch (e) { groqErr = String(e && e.message || e).slice(0, 200); }

// 3) build row
const row = Object.assign({}, lead, {
  enriched_description: enriched,
  icp_score: parsed.icp_score || "NO_MATCH",
  numeric_score: (typeof parsed.numeric_score === "number") ? parsed.numeric_score : null,
  icp_reasoning: parsed.reasoning || null,
  latam_signal: (typeof parsed.latam_signal === "boolean") ? parsed.latam_signal : null,
  ai_signal: (typeof parsed.ai_signal === "boolean") ? parsed.ai_signal : null,
  growth_signal: (typeof parsed.growth_signal === "boolean") ? parsed.growth_signal : null,
  priority_action: parsed.priority_action || null,
  personalization_hook: parsed.personalization_hook || null,
  outreach_status: "pending"
});

// 4) Supabase upsert (dedup on domain)
let stored = false, supaErr = null;
try {
  await this.helpers.httpRequest({
    method: "POST", url: ENV.SUPABASE_URL + "/rest/v1/leads?on_conflict=domain",
    headers: { apikey: ENV.SUPABASE_ANON_KEY, Authorization: "Bearer " + ENV.SUPABASE_ANON_KEY, "Content-Type": "application/json", Prefer: "resolution=merge-duplicates,return=representation" },
    body: row, json: true, timeout: 20000
  });
  stored = true;
} catch (e) { supaErr = String(e && e.message || e).slice(0, 300); }

return [{ json: {
  status: "ok", stored, fcErr, groqErr, supaErr,
  summary: { company: lead.company, domain: lead.domain, icp_score: row.icp_score, numeric_score: row.numeric_score, priority_action: row.priority_action }
} }];
